using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool, Description("Fetches data from an external API at the given path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("Relative API path to query, e.g. \"users/42\".")] string path,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        using var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Re-serialize to guarantee valid, compact JSON output.
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc.RootElement);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum length hint, e.g. \"2 sentences\".")] string? maxLength = null)
    {
        var constraint = string.IsNullOrWhiteSpace(maxLength)
            ? string.Empty
            : $" Keep the summary within {maxLength}.";

        return
        [
            new()
            {
                Role = Role.User,
                Content = new TextContentBlock
                {
                    Text = $"Please provide a concise summary of the following text.{constraint}\n\n{text}"
                }
            }
        ];
    }
}

